// NewThingModelClient returns a client for the ThingModel from the given config.
func NewThingModelClient(c config) *ThingModelClient {
	return &ThingModelClient{config: c}
}

// Use adds a list of mutation hooks to the hooks stack.
// A call to `Use(f, g, h)` equals to `thingmodel.Hooks(f(g(h())))`.
func (c *ThingModelClient) Use(hooks ...Hook) {
	c.hooks.ThingModel = append(c.hooks.ThingModel, hooks...)
}

// Intercept adds a list of query interceptors to the interceptors stack.
// A call to `Intercept(f, g, h)` equals to `thingmodel.Intercept(f(g(h())))`.
func (c *ThingModelClient) Intercept(interceptors ...Interceptor) {
	c.inters.ThingModel = append(c.inters.ThingModel, interceptors...)
}

// Create returns a builder for creating a ThingModel entity.
func (c *ThingModelClient) Create() *ThingModelCreate {
	mutation := newThingModelMutation(c.config, OpCreate)
	return &ThingModelCreate{config: c.config, hooks: c.Hooks(), mutation: mutation}
}

// CreateBulk returns a builder for creating a bulk of ThingModel entities.
func (c *ThingModelClient) CreateBulk(builders ...*ThingModelCreate) *ThingModelCreateBulk {
	return &ThingModelCreateBulk{config: c.config, builders: builders}
}

// MapCreateBulk creates a bulk creation builder from the given slice. For each item in the slice, the function creates
// a builder and applies setFunc on it.
func (c *ThingModelClient) MapCreateBulk(slice any, setFunc func(*ThingModelCreate, int)) *ThingModelCreateBulk {
	rv := reflect.ValueOf(slice)
	if rv.Kind() != reflect.Slice {
		return &ThingModelCreateBulk{err: fmt.Errorf("calling to ThingModelClient.MapCreateBulk with wrong type %T, need slice", slice)}
	}
	builders := make([]*ThingModelCreate, rv.Len())
	for i := 0; i < rv.Len(); i++ {
		builders[i] = c.Create()
		setFunc(builders[i], i)
	}
	return &ThingModelCreateBulk{config: c.config, builders: builders}
}

